Path('governance/channels').mkdir(parents=True, exist_ok=True)
Path('governance/messages').mkdir(parents=True, exist_ok=True)
Path('governance/reports').mkdir(parents=True, exist_ok=True)
Path('governance/runtime/curator_dispatch').mkdir(parents=True, exist_ok=True)

envelope_schema = {
  'status':'active',
  'schema_name':'managed_channel_message_envelope',
  'required_fields':['message_id','task_id','trace_id','source_object','source_curator','target_object','target_curator','message_type','payload_ref','created_at_utc3','rule_refs','status'],
  'allowed_message_types':['task','result','blocker','risk_warning','rule_update','testing_assignment','feedback'],
  'routing_rule':'external object exchange must be curator-to-curator',
  'append_only_log':'governance/messages/managed_channel_messages.jsonl'
}
Path('governance/state/message_envelope_schema.json').write_text(json.dumps(envelope_schema, ensure_ascii=False, indent=2), encoding='utf-8')

def make_msg(mid, task, trace, src_obj, src_cur, dst_obj, dst_cur, mtype, payload, rules):
    return {'message_id':mid,'task_id':task,'trace_id':trace,'source_object':src_obj,'source_curator':src_cur,'target_object':dst_obj,'target_curator':dst_cur,'message_type':mtype,'payload_ref':payload,'created_at_utc3':'2026-05-29T23:35:00+03:00','rule_refs':rules,'status':'recorded'}
messages = [
 make_msg('MSG-BEM885-001','BEM-882-003','bem885_channel_envelope','OBJ-WRK-001','EL-CUR-WRK-001','OBJ-DIR-001','EL-CUR-DIR-001','result','governance/channels/BEM885_MESSAGE_ENVELOPE.md',['RULE-006','RULE-011']),
 make_msg('MSG-BEM885-002','BEM-882-003','bem885_channel_envelope','OBJ-DIR-001','EL-CUR-DIR-001','OBJ-WRK-001','EL-CUR-WRK-001','task','governance/state/message_envelope_schema.json',['RULE-006'])
]
log = Path('governance/messages/managed_channel_messages.jsonl')
existing = log.read_text(encoding='utf-8') if log.exists() else ''
existing_ids = set()
for line in existing.splitlines():
    try:
        item = json.loads(line)
        existing_ids.add(item.get('message_id'))
    except Exception:
        pass
append_lines = []
for m in messages:
    if m['message_id'] not in existing_ids:
        append_lines.append(json.dumps(m, ensure_ascii=False))
if append_lines:
    log.write_text(existing + ('\n' if existing and not existing.endswith('\n') else '') + '\n'.join(append_lines) + '\n', encoding='utf-8')

errors = []
for line in log.read_text(encoding='utf-8').splitlines():
    try:
        msg = json.loads(line)
        for f in envelope_schema['required_fields']:
            if f not in msg:
                errors.append(msg.get('message_id','unknown') + ': missing ' + f)
        if msg.get('message_type') not in envelope_schema['allowed_message_types']:
            errors.append(msg.get('message_id','unknown') + ': invalid message_type')
        if not str(msg.get('source_curator','')).startswith('EL-CUR-') or not str(msg.get('target_curator','')).startswith('EL-CUR-'):
            errors.append(msg.get('message_id','unknown') + ': curator route missing')
    except Exception:
        errors.append('invalid jsonl line')
status = 'PASS' if not errors else 'FAIL'

Path('governance/channels/BEM885_MESSAGE_ENVELOPE.md').write_text('# BEM-885 Managed channel message envelope\n\nStatus: ' + status + '\n\nThe managed channel now has an executable message envelope schema and append-only JSONL message log.\n\nExternal object exchange is curator-to-curator only.\n\nLog: governance/messages/managed_channel_messages.jsonl\n', encoding='utf-8')
Path('governance/reports/BEM885_CHANNEL_ENVELOPE_VALIDATION.md').write_text('# BEM-885 channel envelope validation\n\nStatus: ' + status + '\n\nMessages checked: ' + str(len(log.read_text(encoding='utf-8').splitlines())) + '\n\nErrors: ' + (', '.join(errors) if errors else 'none') + '\n', encoding='utf-8')
marker = Path('governance/runtime/curator_dispatch/BEM885_CHANNEL_ENVELOPE_' + status + '.md')
marker.write_text('# BEM-885 channel envelope proof\nStatus: ' + status + '\nErrors: ' + (', '.join(errors) if errors else 'none') + '\n', encoding='utf-8')

backlog = Path('governance/backlog/BEM882_EXECUTABLE_BACKLOG.json')
if backlog.exists():
    b = json.loads(backlog.read_text(encoding='utf-8'))
    for item in b.get('items', []):
        if item.get('id') == 'BEM-882-003':
            item['status'] = 'completed'
            item['proof'] = str(marker)
        elif 'status' not in item:
            item['status'] = 'pending'
    backlog.write_text(json.dumps(b, ensure_ascii=False, indent=2), encoding='utf-8')

changed_files.extend(['governance/state/message_envelope_schema.json','governance/messages/managed_channel_messages.jsonl','governance/channels/BEM885_MESSAGE_ENVELOPE.md','governance/reports/BEM885_CHANNEL_ENVELOPE_VALIDATION.md',str(marker),'governance/backlog/BEM882_EXECUTABLE_BACKLOG.json'])
ops_applied.append('BEM885 channel envelope ' + status)
